import pandas as pd
df = pd.DataFrame({"cliente_id": ["C001"], "region": ["Lima"], "score": [0.5]})
exact = bool(df.duplicated(keep=False).any())
conflict = df.groupby("cliente_id")["region"].nunique().gt(1).any()
if exact:
    print("exact")
elif conflict:
    print("conflict")
else:
    print("clean")

